/**
 * Theme API Service
 * Wrapper for theme-related API endpoints
 */

import axios from 'axios';
import type { ThemeConfig, CloudThemeInfo } from '@/core/theme/ThemeManager';

const API_BASE = '/api';

/**
 * Theme list query parameters
 */
export interface ThemeListParams {
  status?: 'on_sale' | 'offline' | 'pending';
  page?: number;
  pageSize?: number;
  keyword?: string;
}

/**
 * Theme upload payload
 */
export interface ThemeUploadPayload {
  name: string;
  author: string;
  price: number;
  config: ThemeConfig;
  description?: string;
  thumbnail?: string;
}

/**
 * API response wrapper
 */
export interface ApiResponse<T> {
  success: boolean;
  message?: string;
  data?: T;
  code?: number;
}

/**
 * Theme API service class
 */
class ThemeApiService {
  private axiosInstance;

  constructor() {
    this.axiosInstance = axios.create({
      baseURL: API_BASE,
      timeout: 30000,
      headers: {
        'Content-Type': 'application/json',
      },
    });

    this.axiosInstance.interceptors.request.use((config) => {
      const token = localStorage.getItem('token');
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
      return config;
    });

    this.axiosInstance.interceptors.response.use(
      (response) => response.data,
      (error) => {
        console.error('[ThemeApi] Request error:', error);
        return Promise.reject(error);
      }
    );
  }

  /**
   * Get theme list
   * GET /api/theme/list?status=on_sale
   */
  async getList(params: ThemeListParams = {}): Promise<ApiResponse<CloudThemeInfo[]>> {
    try {
      const response = await this.axiosInstance.get('/theme/list', { params });
      return {
        success: true,
        data: response.data?.items || response.data || [],
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to fetch theme list',
      };
    }
  }

  /**
   * Get my uploaded cloud themes
   * GET /api/theme/my-cloud-themes
   */
  async getMyThemes(): Promise<ApiResponse<CloudThemeInfo[]>> {
    try {
      const response = await this.axiosInstance.get('/theme/my-cloud-themes');
      return {
        success: true,
        data: response.data?.items || response.data || [],
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to fetch my themes',
      };
    }
  }

  /**
   * Upload theme to cloud
   * POST /api/theme/upload
   */
  async upload(payload: ThemeUploadPayload): Promise<ApiResponse<CloudThemeInfo>> {
    try {
      const response = await this.axiosInstance.post('/theme/upload', payload);
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to upload theme',
      };
    }
  }

  /**
   * Buy a theme
   * POST /api/theme/buy
   */
  async buy(themeId: string): Promise<ApiResponse<{ success: boolean }>> {
    try {
      const response = await this.axiosInstance.post('/theme/buy', { themeId });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to purchase theme',
      };
    }
  }

  /**
   * Download a theme
   * GET /api/theme/download?id=xxx
   */
  async download(themeId: string): Promise<ApiResponse<{ config: ThemeConfig }>> {
    try {
      const response = await this.axiosInstance.get('/theme/download', {
        params: { id: themeId },
      });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to download theme',
      };
    }
  }

  /**
   * Toggle theme sale status
   * POST /api/theme/toggle-sale
   */
  async toggleSale(themeId: string, onSale: boolean): Promise<ApiResponse<{ success: boolean }>> {
    try {
      const response = await this.axiosInstance.post('/theme/toggle-sale', {
        themeId,
        onSale,
      });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to toggle sale status',
      };
    }
  }

  /**
   * Get creator earnings
   * GET /api/theme/earnings
   */
  async getEarnings(): Promise<
    ApiResponse<{ total: number; pending: number; withdrawn: number }>
  > {
    try {
      const response = await this.axiosInstance.get('/theme/earnings');
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        data: { total: 0, pending: 0, withdrawn: 0 },
      };
    }
  }

  /**
   * Get theme details
   * GET /api/theme/detail?id=xxx
   */
  async getDetail(themeId: string): Promise<ApiResponse<CloudThemeInfo>> {
    try {
      const response = await this.axiosInstance.get('/theme/detail', {
        params: { id: themeId },
      });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to fetch theme details',
      };
    }
  }

  /**
   * Update theme info
   * POST /api/theme/update
   */
  async update(
    themeId: string,
    payload: Partial<ThemeUploadPayload>
  ): Promise<ApiResponse<CloudThemeInfo>> {
    try {
      const response = await this.axiosInstance.post('/theme/update', {
        themeId,
        ...payload,
      });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to update theme',
      };
    }
  }

  /**
   * Delete theme
   * POST /api/theme/delete
   */
  async delete(themeId: string): Promise<ApiResponse<{ success: boolean }>> {
    try {
      const response = await this.axiosInstance.post('/theme/delete', { themeId });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to delete theme',
      };
    }
  }

  /**
   * Withdraw earnings
   * POST /api/theme/withdraw
   */
  async withdraw(amount: number): Promise<ApiResponse<{ success: boolean }>> {
    try {
      const response = await this.axiosInstance.post('/theme/withdraw', { amount });
      return {
        success: true,
        data: response.data,
      };
    } catch (error: any) {
      return {
        success: false,
        message: error.message || 'Failed to withdraw',
      };
    }
  }
}

export const themeApi = new ThemeApiService();
export default themeApi;
