<template>
  <div class="creator-center-container">
    <!-- 顶部导航栏 -->
    <BaseHeader variant="kids" :showThemeSwitcher="false">
      <template #left>
        <h1 class="logo">
          <span class="logo-icon">🎨</span>
          <span class="logo-text">创作者中心</span>
        </h1>
      </template>
      <template #center>
        <div class="nav-tabs">
          <button 
            v-for="tab in tabs" 
            :key="tab.id"
            :class="['nav-tab', { active: currentTab === tab.id }]"
            @click="currentTab = tab.id"
          >
            <span class="tab-icon">{{ tab.icon }}</span>
            <span class="tab-label">{{ tab.label }}</span>
          </button>
        </div>
      </template>
      <template #right>
        <div class="creator-stats">
          <div class="stat-item">
            <span class="stat-icon">💰</span>
            <span class="stat-value">{{ earnings.total }}</span>
            <span class="stat-label">总收益</span>
          </div>
          <div class="stat-item">
            <span class="stat-icon">📊</span>
            <span class="stat-value">{{ stats.themeCount }}</span>
            <span class="stat-label">主题数</span>
          </div>
          <div class="stat-item">
            <span class="stat-icon">👥</span>
            <span class="stat-value">{{ stats.followerCount }}</span>
            <span class="stat-label">粉丝</span>
          </div>
        </div>
      </template>
    </BaseHeader>

    <!-- 主内容区域 -->
    <main class="creator-main">
      <!-- 我的主题管理 -->
      <section v-if="currentTab === 'my-themes'" class="section my-themes">
        <div class="section-header">
          <h2 class="section-title">我的主题</h2>
          <button class="btn-create" @click="startCreateTheme">
            <span class="btn-icon">+</span>
            <span class="btn-text">创建新主题</span>
          </button>
        </div>
        
        <div v-if="loading" class="loading-state">
          <div class="loading-spinner"></div>
          <p>加载中...</p>
        </div>

        <div v-else-if="myThemes.length === 0" class="empty-state">
          <div class="empty-illustration">🎨</div>
          <h3>还没有创建主题</h3>
          <p>开始创作你的第一个主题吧！</p>
          <button class="btn-create-empty" @click="startCreateTheme">
            创建第一个主题
          </button>
        </div>

        <div v-else class="themes-grid">
          <div 
            v-for="theme in myThemes" 
            :key="theme.id"
            class="theme-card"
            :class="{ 'on-sale': theme.status === 'on_sale' }"
          >
            <div class="theme-thumbnail" @click="editTheme(theme)">
              <img 
                v-if="theme.thumbnail" 
                :src="theme.thumbnail" 
                :alt="theme.name"
                class="thumbnail-img"
              />
              <div v-else class="thumbnail-placeholder">
                <span>{{ theme.name.charAt(0) }}</span>
              </div>
              <div v-if="theme.status === 'on_sale'" class="sale-badge">销售中</div>
              <div v-else class="offline-badge">已下架</div>
              <div class="theme-price">
                {{ theme.price > 0 ? `${theme.price} 趣乐币` : '免费' }}
              </div>
            </div>
            
            <div class="theme-info">
              <h3 class="theme-name">{{ theme.name }}</h3>
              <div class="theme-meta">
                <span class="theme-downloads">
                  <span class="meta-icon">⬇️</span>
                  {{ theme.downloadCount || 0 }}
                </span>
                <span v-if="theme.rating" class="theme-rating">
                  <span class="meta-icon">⭐</span>
                  {{ theme.rating.toFixed(1) }}
                </span>
                <span class="theme-earnings">
                  <span class="meta-icon">💰</span>
                  {{ theme.earnings || 0 }} 趣乐币
                </span>
              </div>
            </div>
            
            <div class="theme-actions">
              <button 
                class="btn-action"
                :class="theme.status === 'on_sale' ? 'btn-offline' : 'btn-online'"
                @click="toggleThemeSale(theme)"
                :disabled="isToggling"
              >
                {{ theme.status === 'on_sale' ? '下架' : '上架' }}
              </button>
              <button class="btn-action btn-edit" @click="editTheme(theme)">
                编辑
              </button>
              <button class="btn-action btn-stats" @click="viewThemeStats(theme)">
                数据
              </button>
            </div>
          </div>
        </div>
      </section>

      <!-- 主题商店 -->
      <section v-else-if="currentTab === 'store'" class="section theme-store">
        <div class="section-header">
          <h2 class="section-title">主题商店</h2>
          <div class="store-filters">
            <button 
              v-for="filter in storeFilters" 
              :key="filter.id"
              :class="['filter-btn', { active: storeFilter === filter.id }]"
              @click="storeFilter = filter.id"
            >
              {{ filter.label }}
            </button>
            <input 
              v-model="searchQuery" 
              type="text" 
              placeholder="搜索主题..." 
              class="search-input"
            />
          </div>
        </div>

        <div v-if="storeLoading" class="loading-state">
          <div class="loading-spinner"></div>
          <p>加载中...</p>
        </div>

        <div v-else-if="storeThemes.length === 0" class="empty-state">
          <div class="empty-illustration">🛍️</div>
          <h3>没有找到主题</h3>
          <p>尝试搜索其他关键词</p>
        </div>

        <div v-else class="store-grid">
          <div 
            v-for="theme in storeThemes" 
            :key="theme.id"
            class="store-theme-card"
            :class="{ owned: theme.owned }"
          >
            <div class="theme-thumbnail" @click="previewTheme(theme)">
              <img 
                v-if="theme.thumbnail" 
                :src="theme.thumbnail" 
                :alt="theme.name"
                class="thumbnail-img"
              />
              <div v-else class="thumbnail-placeholder">
                <span>{{ theme.name.charAt(0) }}</span>
              </div>
              <div v-if="theme.price === 0" class="free-badge">免费</div>
            </div>
            
            <div class="theme-info">
              <h3 class="theme-name">{{ theme.name }}</h3>
              <p class="theme-author">作者：{{ theme.author }}</p>
              <div class="theme-meta">
                <span class="theme-downloads">
                  <span class="meta-icon">⬇️</span>
                  {{ theme.downloadCount || 0 }}
                </span>
                <span v-if="theme.rating" class="theme-rating">
                  <span class="meta-icon">⭐</span>
                  {{ theme.rating.toFixed(1) }}
                </span>
              </div>
            </div>
            
            <div class="theme-footer">
              <div class="theme-price">
                {{ theme.price > 0 ? `${theme.price} 趣乐币` : '免费' }}
              </div>
              <button 
                class="btn-buy"
                :class="{ owned: theme.owned }"
                @click="handleBuyOrDownload(theme)"
                :disabled="isPurchasing"
              >
                {{ theme.owned ? '已拥有' : theme.price > 0 ? '购买' : '获取' }}
              </button>
            </div>
          </div>
        </div>
      </section>

      <!-- 主题创作 -->
      <section v-else-if="currentTab === 'create'" class="section theme-create">
        <div class="create-container">
          <div class="create-header">
            <h2 class="create-title">主题创作</h2>
            <p class="create-subtitle">打造属于你的个性化主题</p>
          </div>
          
          <div class="create-steps">
            <div 
              v-for="(step, index) in createSteps" 
              :key="step.id"
              :class="['create-step', { active: createStep === step.id }]"
            >
              <div class="step-number">{{ index + 1 }}</div>
              <div class="step-info">
                <h4 class="step-title">{{ step.title }}</h4>
                <p class="step-description">{{ step.description }}</p>
              </div>
            </div>
          </div>

          <!-- 基本信息步骤 -->
          <div v-if="createStep === 'info'" class="step-content info-step">
            <div class="form-group">
              <label class="form-label">主题名称</label>
              <input 
                v-model="newTheme.name" 
                type="text" 
                placeholder="输入主题名称" 
                class="form-input"
              />
            </div>
            <div class="form-group">
              <label class="form-label">作者名称</label>
              <input 
                v-model="newTheme.author" 
                type="text" 
                placeholder="输入作者名称" 
                class="form-input"
              />
            </div>
            <div class="form-group">
              <label class="form-label">基于模板</label>
              <select v-model="newTheme.baseThemeKey" class="form-input">
                <option v-for="theme in baseThemes" :key="theme.key" :value="theme.key">
                  {{ theme.name }}
                </option>
              </select>
            </div>
            <div class="form-group">
              <label class="form-label">主题描述</label>
              <textarea 
                v-model="newTheme.description" 
                placeholder="描述你的主题特点..." 
                class="form-textarea"
                rows="3"
              ></textarea>
            </div>
            <div class="form-group">
              <label class="form-label">定价（趣乐币）</label>
              <input 
                v-model="newTheme.price" 
                type="number" 
                min="0" 
                class="form-input"
                placeholder="0 表示免费"
              />
              <div class="form-hint">设置 0 为免费主题，其他为付费主题</div>
            </div>
          </div>

          <!-- 样式配置步骤 -->
          <div v-else-if="createStep === 'styles'" class="step-content styles-step">
            <div class="style-editor">
              <div class="style-preview">
                <div class="preview-card" :style="previewStyles">
                  <h3 class="preview-title" :style="{ color: newThemeStyles.color_text }">
                    {{ newTheme.name || '主题预览' }}
                  </h3>
                  <button 
                    class="preview-button"
                    :style="{
                      backgroundColor: newThemeStyles.color_primary,
                      borderRadius: newThemeStyles.border_radius_btn,
                    }"
                  >
                    示例按钮
                  </button>
                </div>
              </div>
              
              <div class="style-controls">
                <div class="style-group">
                  <h4 class="style-group-title">颜色配置</h4>
                  <div class="color-grid">
                    <div v-for="key in colorKeys" :key="key" class="color-field">
                      <label class="color-label">{{ formatStyleKey(key) }}</label>
                      <div class="color-input-wrapper">
                        <input 
                          v-model="newThemeStyles[key]"
                          type="color"
                          class="color-picker"
                        />
                        <input 
                          v-model="newThemeStyles[key]"
                          type="text"
                          class="color-text-input"
                          placeholder="#000000"
                        />
                      </div>
                    </div>
                  </div>
                </div>
                
                <div class="style-group">
                  <h4 class="style-group-title">尺寸配置</h4>
                  <div class="size-grid">
                    <div v-for="key in sizeKeys" :key="key" class="size-field">
                      <label class="size-label">{{ formatStyleKey(key) }}</label>
                      <input 
                        v-model="newThemeStyles[key]"
                        type="text"
                        class="size-input"
                        placeholder="8px"
                      />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- 资源上传步骤 -->
          <div v-else-if="createStep === 'assets'" class="step-content assets-step">
            <div class="asset-uploader">
              <div class="asset-list">
                <div v-for="key in assetKeys" :key="key" class="asset-item">
                  <div class="asset-info">
                    <span class="asset-key">{{ formatAssetKey(key) }}</span>
                    <span v-if="newThemeAssets[key]" class="asset-name">
                      {{ getAssetName(newThemeAssets[key]) }}
                    </span>
                  </div>
                  <div class="asset-actions">
                    <label class="btn-upload">
                      <input 
                        type="file"
                        :accept="getFileAccept(key)"
                        @change="(e) => handleAssetUpload(key, e)"
                        class="hidden"
                      />
                      上传文件
                    </label>
                    <button 
                      v-if="newThemeAssets[key]"
                      class="btn-preview"
                      @click="previewAsset(key)"
                    >
                      预览
                    </button>
                  </div>
                </div>
              </div>
              
              <div class="asset-preview">
                <h4 class="preview-title">资源预览</h4>
                <div class="preview-grid">
                  <div 
                    v-for="(path, key) in newThemeAssets" 
                    :key="key"
                    class="preview-item"
                  >
                    <div v-if="isImage(path)" class="image-preview">
                      <img :src="path" :alt="key" class="preview-img" />
                    </div>
                    <div v-else class="audio-preview">
                      <span class="audio-icon">🎵</span>
                      <span class="audio-name">{{ key }}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- 发布设置步骤 -->
          <div v-else-if="createStep === 'publish'" class="step-content publish-step">
            <div class="publish-summary">
              <div class="summary-card">
                <h4 class="summary-title">主题信息</h4>
                <div class="summary-item">
                  <span class="item-label">主题名称：</span>
                  <span class="item-value">{{ newTheme.name }}</span>
                </div>
                <div class="summary-item">
                  <span class="item-label">作者名称：</span>
                  <span class="item-value">{{ newTheme.author }}</span>
                </div>
                <div class="summary-item">
                  <span class="item-label">定价：</span>
                  <span class="item-value">
                    {{ newTheme.price > 0 ? `${newTheme.price} 趣乐币` : '免费' }}
                  </span>
                </div>
                <div class="summary-item">
                  <span class="item-label">资源数量：</span>
                  <span class="item-value">
                    {{ Object.keys(newThemeAssets).length }} 个
                  </span>
                </div>
              </div>
              
              <div class="publish-options">
                <div class="option-group">
                  <label class="option-label">
                    <input 
                      v-model="publishOptions.saveLocally" 
                      type="checkbox" 
                      class="option-checkbox"
                    />
                    保存到本地
                  </label>
                  <p class="option-description">保存主题到本地库，方便后续编辑</p>
                </div>
                <div class="option-group">
                  <label class="option-label">
                    <input 
                      v-model="publishOptions.uploadToStore" 
                      type="checkbox" 
                      class="option-checkbox"
                    />
                    发布到商店
                  </label>
                  <p class="option-description">将主题发布到主题商店，其他用户可以购买</p>
                </div>
                <div v-if="publishOptions.uploadToStore" class="option-group">
                  <label class="option-label">发布状态</label>
                  <select v-model="publishOptions.publishStatus" class="option-select">
                    <option value="draft">草稿</option>
                    <option value="on_sale">立即上架</option>
                  </select>
                </div>
              </div>
            </div>
          </div>

          <!-- 导航按钮 -->
          <div class="create-navigation">
            <button 
              v-if="createStep !== 'info'" 
              class="btn-nav btn-prev"
              @click="prevStep"
            >
              上一步
            </button>
            <button 
              v-if="createStep !== 'publish'" 
              class="btn-nav btn-next"
              @click="nextStep"
              :disabled="!canProceed"
            >
              下一步
            </button>
            <button 
              v-if="createStep === 'publish'" 
              class="btn-nav btn-publish"
              @click="publishTheme"
              :disabled="!canPublish"
            >
              发布主题
            </button>
          </div>
        </div>
      </section>

      <!-- 主题切换 -->
      <section v-else-if="currentTab === 'theme-switcher'" class="section theme-switcher">
        <div class="switcher-container">
          <div class="switcher-header">
            <h2 class="switcher-title">切换主题</h2>
            <p class="switcher-subtitle">选择您喜欢的主题应用到系统中</p>
          </div>
          
          <div v-if="loadingThemes" class="loading-state">
            <div class="loading-spinner"></div>
            <p>加载主题中...</p>
          </div>
          
          <div v-else class="themes-grid-switcher">
            <div 
              v-for="theme in availableThemes" 
              :key="theme.id"
              class="theme-option-switcher"
              :class="{ active: currentTheme?.id === theme.id }"
              @click="switchTheme(theme.id)"
            >
              <div class="theme-preview" :style="{ background: theme.previewColor }">
                <div class="color-palette">
                  <span 
                    v-for="(color, index) in theme.colorPalette" 
                    :key="index"
                    class="color-swatch"
                    :style="{ backgroundColor: color }"
                  ></span>
                </div>
              </div>
              
              <div class="theme-info-switcher">
                <h3 class="theme-name-switcher">{{ theme.name }}</h3>
                <p class="theme-description-switcher">{{ theme.description || '这是一个漂亮的主题' }}</p>
                <div class="theme-meta-switcher">
                  <span class="theme-type">
                    {{ theme.type === 'system' ? '系统' : '自定义' }}
                  </span>
                  <span v-if="theme.price === 0" class="theme-price-free">免费</span>
                  <span v-else class="theme-price-paid">{{ theme.price }} 趣乐币</span>
                </div>
              </div>
              
              <div class="theme-status">
                <span v-if="currentTheme?.id === theme.id" class="status-active">
                  ✓ 已启用
                </span>
                <button v-else class="btn-apply" @click.stop="switchTheme(theme.id)">
                  应用主题
                </button>
              </div>
            </div>
          </div>
          
          <div v-if="availableThemes.length === 0 && !loadingThemes" class="empty-state">
            <div class="empty-illustration">🎨</div>
            <h3>暂无可用主题</h3>
            <p>请先创建或下载主题</p>
            <button class="btn-create-switcher" @click="currentTab = 'create'">
              创建主题
            </button>
          </div>
        </div>
      </section>

      <!-- 数据统计 -->
      <section v-else-if="currentTab === 'stats'" class="section creator-stats">
        <div class="stats-container">
          <div class="stats-header">
            <h2 class="stats-title">数据统计</h2>
            <div class="stats-period">
              <select v-model="statsPeriod" class="period-select">
                <option value="7d">最近7天</option>
                <option value="30d">最近30天</option>
                <option value="90d">最近90天</option>
                <option value="all">全部时间</option>
              </select>
            </div>
          </div>
          
          <div class="stats-grid">
            <div class="stat-card">
              <div class="stat-icon">💰</div>
              <div class="stat-info">
                <div class="stat-value">{{ earnings.total }}</div>
                <div class="stat-label">总收益</div>
                <div class="stat-change" :class="earnings.change >= 0 ? 'positive' : 'negative'">
                  {{ earnings.change >= 0 ? '+' : '' }}{{ earnings.change }}%
                </div>
              </div>
            </div>
            
            <div class="stat-card">
              <div class="stat-icon">📈</div>
              <div class="stat-info">
                <div class="stat-value">{{ stats.downloads }}</div>
                <div class="stat-label">总下载量</div>
                <div class="stat-change" :class="stats.downloadChange >= 0 ? 'positive' : 'negative'">
                  {{ stats.downloadChange >= 0 ? '+' : '' }}{{ stats.downloadChange }}%
                </div>
              </div>
            </div>
            
            <div class="stat-card">
              <div class="stat-icon">👥</div>
              <div class="stat-info">
                <div class="stat-value">{{ stats.followerCount }}</div>
                <div class="stat-label">粉丝数</div>
                <div class="stat-change" :class="stats.followerChange >= 0 ? 'positive' : 'negative'">
                  {{ stats.followerChange >= 0 ? '+' : '' }}{{ stats.followerChange }}%
                </div>
              </div>
            </div>
            
            <div class="stat-card">
              <div class="stat-icon">⭐</div>
              <div class="stat-info">
                <div class="stat-value">{{ stats.averageRating.toFixed(1) }}</div>
                <div class="stat-label">平均评分</div>
                <div class="stat-change" :class="stats.ratingChange >= 0 ? 'positive' : 'negative'">
                  {{ stats.ratingChange >= 0 ? '+' : '' }}{{ stats.ratingChange }}分
                </div>
              </div>
            </div>
          </div>
          
          <div class="charts-section">
            <div class="chart-card">
              <h4 class="chart-title">收益趋势</h4>
              <div class="chart-placeholder">
                <div class="chart-empty">📈 图表待实现</div>
              </div>
            </div>
            
            <div class="chart-card">
              <h4 class="chart-title">主题下载量</h4>
              <div class="chart-placeholder">
                <div class="chart-empty">📊 图表待实现</div>
              </div>
            </div>
          </div>
        </div>
      </section>
    </main>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, reactive, onMounted } from 'vue';
import { useRouter, useRoute } from 'vue-router';
import BaseHeader from '@/components/layout/BaseHeader.vue';
import { themeManager } from '@/core/theme/ThemeManager';
import type { 
  CloudThemeInfo, 
  ThemeConfig, 
  DiyThemeData 
} from '@/core/theme/ThemeManager';

const router = useRouter();
const route = useRoute();

// 标签页配置
const tabs = [
  { id: 'my-themes', label: '我的主题', icon: '🎨' },
  { id: 'store', label: '主题商店', icon: '🛍️' },
  { id: 'create', label: '主题创作', icon: '✨' },
  { id: 'theme-switcher', label: '切换主题', icon: '🎯' },
  { id: 'stats', label: '数据统计', icon: '📊' },
];

// 当前活动标签页
const currentTab = ref('my-themes');

// 商店筛选器
const storeFilters = [
  { id: 'all', label: '全部' },
  { id: 'free', label: '免费' },
  { id: 'paid', label: '付费' },
  { id: 'hot', label: '热门' },
  { id: 'new', label: '最新' },
];
const storeFilter = ref('all');

// 主题切换相关
const loadingThemes = ref(false);
const availableThemes = ref<any[]>([]);
const currentTheme = ref<any>(null);
const searchQuery = ref('');

// 创作者数据
const earnings = reactive({
  total: 0,
  pending: 0,
  withdrawn: 0,
  change: 12.5,
});

const stats = reactive({
  themeCount: 0,
  followerCount: 0,
  downloads: 0,
  downloadChange: 8.3,
  averageRating: 4.5,
  ratingChange: 0.2,
  followerChange: 5.7,
});

const statsPeriod = ref('30d');

// 我的主题
const loading = ref(false);
const isToggling = ref(false);
