    colorKeys.value = themeManager.getBaseStyleKeys().filter(key => 
      key.toLowerCase().includes('color')
    );
    sizeKeys.value = themeManager.getBaseStyleKeys().filter(key => 
      key.toLowerCase().includes('size') || 
      key.toLowerCase().includes('radius')
