// 开始创建主题
function startCreateTheme(): void {
  currentTab.value = 'create';
  createStep.value = 'info';
  resetNewTheme();
}

// 重置新主题
function resetNewTheme(): void {
  newTheme.name = '';
  newTheme.author = '';
  newTheme.baseThemeKey = 'default';
  newTheme.description = '';
  newTheme.price = 0;
  
  Object.keys(newThemeStyles).forEach(key => {
    delete newThemeStyles[key];
  });
  
  Object.keys(newThemeAssets).forEach(key => {
    delete newThemeAssets[key];
  });
}

// 格式样式键
function formatStyleKey(key: string): string {
  return key
    .replace(/_/g, ' ')
    .replace(/\b\w/g, (l) => l.toUpperCase());
}

// 格式资产键
function formatAssetKey(key: string): string {
  return key.replace(/_/g, ' ');
}

// 获取文件接受类型
function getFileAccept(key: string): string {
  if (key.includes('bgm') || key.includes('sound') || key.includes('audio')) {
    return 'audio/*';
  }
  return 'image/*';
}

// 检查是否为图片
function isImage(path: string): boolean {
  return /\.(png|jpg|jpeg|webp|gif)$/i.test(path);
}

// 获取资产名称
function getAssetName(path: string): string {
  if (path.startsWith('data:')) {
    return '上传的文件';
  }
  return path.split('/').pop() || '文件';
}

// 处理资产上传
function handleAssetUpload(key: string, event: Event): void {
  const input = event.target as HTMLInputElement;
  const file = input.files?.[0];
  if (!file) return;
  
  const reader = new FileReader();
  reader.onload = (e) => {
    const result = e.target?.result as string;
    newThemeAssets[key] = result;
  };
  reader.readAsDataURL(file);
}

// 预览资产
function previewAsset(key: string): void {
  const path = newThemeAssets[key];
  if (!path) return;
  
  if (isImage(path)) {
    const img = new Image();
    img.src = path;
    const win = window.open('', '_blank');
    win?.document.write(img.outerHTML || '');
  } else {
    const audio = new Audio(path);
    audio.play();
  }
}

// 上一步
function prevStep(): void {
  const steps = createSteps.map(step => step.id);
  const currentIndex = steps.indexOf(createStep.value);
  if (currentIndex > 0) {
    createStep.value = steps[currentIndex - 1];
  }
}

// 下一步
function nextStep(): void {
  const steps = createSteps.map(step => step.id);
  const currentIndex = steps.indexOf(createStep.value);
  if (currentIndex < steps.length - 1) {
    createStep.value = steps[currentIndex + 1];
  }
}

// 发布主题
async function publishTheme(): Promise<void> {
  if (!canPublish.value) return;
  
  try {
    const themeData: DiyThemeData = {
      baseThemeKey: newTheme.baseThemeKey,
      name: newTheme.name,
      author: newTheme.author,
      assetOverrides: { ...newThemeAssets },
      styleOverrides: { ...newThemeStyles },
      createdAt: Date.now(),
      updatedAt: Date.now(),
    };
    
    if (publishOptions.saveLocally) {
      const themeKey = themeManager.addLocalDiyTheme(themeData);
      console.log('Theme saved locally:', themeKey);
    }
    
    if (publishOptions.uploadToStore) {
      const result = await themeManager.uploadDiyToCloud(
        themeData.name,
        newTheme.price,
        newTheme.description,
        themeData.assetOverrides,
        themeData.styleOverrides
      );
      if (result) {
        alert('主题发布成功！');
        // 重置表单
        resetNewTheme();
        createStep.value = 'info';
        // 重新加载我的主题
        await loadMyThemes();
        // 切换到我的主题页面
        currentTab.value = 'my-themes';
      } else {
        alert('发布失败，请重试');
      }
    } else {
      alert('主题已保存到本地！');
      resetNewTheme();
      createStep.value = 'info';
    }
  } catch (e) {
    console.error('[CreatorCenter] Publish failed:', e);
    alert('发布失败');
  }
}

// 购买或下载主题
async function handleBuyOrDownload(theme: CloudThemeInfo): Promise<void> {
  if (theme.owned) {
    await downloadTheme(theme.id);
    return;
  }
  
  if (theme.price > 0) {
    // 显示购买确认
    if (confirm(`确定要购买主题 "${theme.name}" 吗？\n价格：${theme.price} 趣乐币`)) {
      await buyTheme(theme);
    }
  } else {
    await downloadTheme(theme.id);
  }
}

